let type = 'Daily';
if ($('Four-hourly Trigger').isExecuted)  type = 'Four-hourly';
else if ($('Daily Trigger').isExecuted)   type = 'Daily';
const paises = [
  { country: 'AR', channelId: '19:KqPHeI2vg9nNHO2de_AHbQGLK2Xh8Ah8iODV2ttJh_k1@thread.tacv2', canal_test: '19:dc98fb5c02394731b1ad9e1524a962b9@thread.tacv2' },
  { country: 'BO', channelId: '19:5e3bf46869f140a39d48f869795379c5@thread.tacv2', canal_test: '19:86a3c7f0143a499d8f125b57ed6bce8f@thread.tacv2' },
  { country: 'CO', channelId: '19:af378cf202564cfc87591f580cd70935@thread.tacv2', canal_test: '19:d0982df38f334f3c9785783c3d9f1e5a@thread.tacv2' },
  { country: 'PE', channelId: '19:d5b204e433134ff5b1f7a90e51d76982@thread.tacv2', canal_test: '19:127b6f887e2e4e148b99c08db9d5dc79@thread.tacv2' },
];
return paises.map(p => ({ json: { ...p, type } }));

const items = $input.all();
for (const item of items) {
  const app = (item.json.application || '').trim();
  // selector de base para el Switch (credencial guardada por nodo)
  item.json.flag = (app === 'COMFIAR 2') ? 'comfiar2' : 'apgcore';

  item.json.hora_ejecucion_real = DateTime.now()
    .setZone('America/Argentina/Buenos_Aires')   // server apgcore = Argentina
    .toFormat("yyyy-MM-dd'T'HH:mm:ss.SSS");
  item.json.audit_startTime = new Date().getTime();
}
return items;

const results = $input.all();
const errorMsg = typeof results[0]?.json?.error === 'string' ? results[0].json.error : null;
const hasError = !!errorMsg;

const now = new Date();
const start = $('Audit Start1').item?.json?.audit_startTime || $('Audit Start1').first().json.audit_startTime;
const e = $('Credentials Loop1').item?.json || {};
const q = $('Query Loop1').item?.json || {};

const isEmpty = results.length === 1 && Object.keys(results[0].json || {}).length === 0;
const realResultsCount = hasError || isEmpty ? 0 : results.length;
const sizeInBytes = hasError ? 0 : JSON.stringify(results.map(r => r.json)).length;

return [{
  json: {
    query:             q.queryId     || 'N/A',
    pais:              e.country      || 'Desconocido',
    entorno:           q.target_env   || 'Desconocido',
    frecuencia:        q.type         || 'N/A',
    description:       q.description  || 'Sin descripción',
    aplicacion:        q.application  || 'N/A',
    tiempo:            +((now - start) / 1000).toFixed(2),
    peso:              +((sizeInBytes / 1024).toFixed(2)),
    filas_encontradas: realResultsCount,
    timestamp_tz:      now.toISOString().split('.')[0].replace('T', ' ') + '+00',
    fecha_real:        now.toLocaleDateString("en-CA", { timeZone: "America/Argentina/Buenos_Aires" }),
    hora_limpia:       now.toLocaleTimeString("en-GB", { timeZone: "America/Argentina/Buenos_Aires" }),
    status:            !hasError,
    error_message:     errorMsg || null
  }
}];

const audit = $('Update Metrics1').first().json;
const ctx   = $('Query Loop1').first().json;
const out   = JSON.parse(JSON.stringify(ctx));

let rows = [], estado;
if (audit.status === false) {
  estado = 'ERROR';
} else {
  rows = $('SQL Execute').all().map(i => i.json).filter(j => Object.keys(j).length > 0);
  estado = rows.length ? 'OK' : 'VACIO';
}

out.result        = rows;
out._status       = estado;          // OK | VACIO | ERROR
out._isError      = audit.status === false;
out._errorMessage = audit.error_message || null;
out.filas         = audit.filas_encontradas;
out.country       = audit.pais;
return { json: out };

// [Set HTML1 - Apps] 1 item por aplicación
const allItems = $input.all();
if (allItems.length === 0) return [];

const rows = allItems.map(i => i.json);
let type = 'General';
try { type = $('Credentials Loop1').first().json['type'] || 'General'; } catch(e) {}

const esc = v => (v == null) ? '' : String(v).replace(/</g, '&lt;').replace(/>/g, '&gt;');

const apps = {};
for (const r of rows) {
  const app = r.application || 'Sin App';
  if (!apps[app]) apps[app] = [];
  apps[app].push(r);
}

const output = [];

for (const [appName, appItems] of Object.entries(apps)) {
  const errores  = appItems.filter(r => r._isError === true);
  const conDatos = appItems.filter(r => !r._isError && Array.isArray(r.result) && r.result.length > 0);
  const vacios   = appItems.filter(r => !r._isError && (!Array.isArray(r.result) || r.result.length === 0));

  if (!errores.length && !conDatos.length && ['Hourly', 'Bi-hourly', 'Nightly'].includes(type)) continue;

  let html = '<div style="font-family:sans-serif;font-size:13px;color:#000;">';
  html += `<h2 style="font-size:16px;font-weight:bold;border-bottom:2px solid #222;padding-bottom:6px;margin:0 0 14px 0;">Revisión ${esc(type)} — ${esc(appName)}</h2>`;

  if (errores.length) {
    html += '<div style="background:#fff3cd;border-left:4px solid #ffc107;padding:8px 12px;margin-bottom:14px;">';
    html += `<b style="color:#856404;">⚠ Queries con error (${errores.length})</b>`;
    html += '<ul style="margin:6px 0 0 0;padding-left:18px;">';
    for (const e of errores) {
      html += `<li style="margin-bottom:4px;"><b>[${esc(e.queryId)}] ${esc(e.description)}</b>`;
      if (e._errorMessage) html += `<br><small style="color:#666;">${esc(String(e._errorMessage).slice(0, 400))}</small>`;
      html += '</li>';
    }
    html += '</ul></div>';
  }

  for (const r of conDatos) {
    html += `<h3 style="font-size:13px;font-weight:bold;margin:12px 0 4px 0;">Punto ${esc(r.queryId)}: ${esc(r.description)}</h3>`;
    const MAX_ROWS = 150, MAX_COLS = 10;
    const data    = r.result.slice(0, MAX_ROWS);
    const allKeys = Object.keys(r.result[0] || {});
    const headers = allKeys.slice(0, MAX_COLS);
    html += '<table border="1" cellpadding="4" cellspacing="0" style="border-collapse:collapse;width:100%;margin-bottom:6px;"><thead><tr bgcolor="#f2f2f2">';
    for (const h of headers) html += `<th align="left">${esc(h)}</th>`;
    html += '</tr></thead><tbody>';
    for (const row of data) {
      html += '<tr>';
      for (const h of headers) html += `<td>${esc(row[h])}</td>`;
      html += '</tr>';
    }
    html += '</tbody></table>';
    if (r.result.length > MAX_ROWS || allKeys.length > MAX_COLS) {
      const notes = [];
      if (r.result.length > MAX_ROWS) notes.push(`${MAX_ROWS} de ${r.result.length} filas`);
      if (allKeys.length > MAX_COLS) notes.push(`${MAX_COLS} de ${allKeys.length} columnas`);
      html += `<p style="font-size:11px;font-style:italic;color:#666;margin:0 0 8px 0;">(Vista limitada: ${notes.join(', ')})</p>`;
    }
    if (String(r.pattern || '').trim() === '2') {
      const q = `-- SELECT\n${r.revisionQuery || ''}\n\n-- UPDATE\n${r.correctionQuery || ''}`;
      html += `<pre style="font-family:monospace;font-size:11px;background:#f4f4f4;padding:8px;border:1px solid #ccc;margin-bottom:8px;">${esc(q)}</pre>`;
    }
  }

  if (!errores.length && !conDatos.length) html += '<p>✅ Sin novedades.</p>';

  if (vacios.length > 0 && (errores.length > 0 || conDatos.length > 0)) {
    html += '<p style="font-size:11px;font-style:italic;color:#666;border-top:1px solid #eee;padding-top:8px;margin-top:12px;">El resto de los puntos no dieron resultados.</p>';
  }

  html += '</div>';
  output.push({ json: { htmlContent: html, application: appName } });
}

return output;
